const cfg = $('Configuration').first().json;
const items = $input.all();
const excludedSenderFragments = ['no-reply','noreply','newsletter','notification','notifications','marketing','facebookmail','linkedin'];
const excludedSubjectFragments = ['newsletter','désabonnement','promotion','notification automatique','absence du bureau','automatic reply'];
const cutoff = new Date(Date.now() - Number(cfg.lookbackHours || 8) * 3600 * 1000);
const prepared = [];
const skipped = [];
for (const item of items) {
  const m = item.json;
  if (m.error) { skipped.push({ reason: 'erreur lecture' }); continue; }
  const headers = m.payload?.headers || [];
  const from = headers.find(h => h.name === 'From')?.value || '';
  const subject = headers.find(h => h.name === 'Subject')?.value || '';
  const date = headers.find(h => h.name === 'Date')?.value || '';
  const senderLower = from.toLowerCase();
  const subjectLower = subject.toLowerCase();
  const receivedAt = date ? new Date(date) : new Date();
  const excludedBySender = excludedSenderFragments.some(x => senderLower.includes(x));
  const excludedBySubject = excludedSubjectFragments.some(x => subjectLower.includes(x));
  const tooOld = receivedAt < cutoff;
  if (excludedBySender || excludedBySubject || tooOld) {
    skipped.push({ subject, sender: from, reason: excludedBySender ? 'expediteur exclu' : excludedBySubject ? 'objet exclu' : 'trop ancien' });
    continue;
  }
  prepared.push({
    id: m.id,
    subject,
    sender: from,
    snippet: (m.snippet || '').substring(0, 500)
  });
}
return [{ json: { emails: prepared, skipped, runAt: new Date().toISOString() } }];

