const source = $('Préparer emails').first().json;
let parsed;
try {
  const content = $json.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch(e) {
  parsed = { emails: [], global_summary: 'Erreur de parsing IA.' };
}
const analyses = parsed.emails || [];
const urgent = analyses.filter(x => x.urgence === 'haute');
const repondre = analyses.filter(x => x.action === 'repondre');
const echeances = analyses.filter(x => x.echeance_detectee);
function line(x) {
  return `• ${x.sender?.split('<')[0]?.trim() || 'Inconnu'} | ${x.subject || '(sans objet)'} | ${x.resume || ''}${x.raison_urgence ? ' — ' + x.raison_urgence : ''}`;
}
const summaryText = [
  `🤖 Synthèse emails Jarvis — ${new Date().toLocaleString('fr-FR')}`,
  '',
  `Emails analysés: ${analyses.length} | Ignorés: ${(source.skipped || []).length}`,
  '',
  '🚨 Urgents',
  urgent.length ? urgent.map(line).join('\n') : '• Aucun email urgent.',
  '',
  '📩 Réponses à préparer',
  repondre.length ? repondre.map(line).join('\n') : '• Aucune réponse prioritaire.',
  '',
  '📅 Échéances détectées',
  echeances.length ? echeances.map(x => `• ${x.date_echeance || 'date à confirmer'} | ${x.subject || ''} | ${x.resume || ''}`).join('\n') : '• Aucune échéance.',
  '',
  '📋 Synthèse générale',
  parsed.global_summary || '• Rien à signaler.'
].join('\n');
return [{ json: { summaryText, processedCount: analyses.length, skippedCount: (source.skipped || []).length } }];
